  "sentences": [
    {
      "text": "我想要一杯小杯的拿鐵。",
      "pinyin": "Wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de0 na2 tie3.",
      "translation_en": "I would like a small latte.",
      "translation_ko": "작은 라떼 한 잔을 원합니다."
    },
    {
      "text": "我想要一杯中杯的紅茶，半糖。",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi de hóng chá, bàn táng.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 de0 hong2 cha2, ban4 tang2.",
      "translation_en": "I would like a medium black tea, half sugar.",
      "translation_ko": "중간 크기의 홍차 반 당을 원합니다."
    },
    {
      "text": "我想要一杯大杯的綠茶，去冰。",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi de lǜ chá, qù bīng.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 de0 lü4 cha2, qu4 bing1.",
      "translation_en": "I would like a large green tea, no ice.",
      "translation_ko": "큰 녹차 한 잔을 얼음 없이 원합니다."
    },
    {
      "text": "我想要一杯豆漿，加珍珠。",
      "pinyin": "Wǒ xiǎng yào yī bēi dòu jiāng, jiā zhēn zhū.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4 jiang1, jia1 zhen1 zhu1.",
      "translation_en": "I would like a cup of soy milk with tapioca pearls.",
      "translation_ko": "두유 한 잔에 타피오카 펄을 추가하고 싶습니다."
    },
    {
      "text": "我想要一杯冰的拿鐵，少冰。",
      "pinyin": "Wǒ xiǎng yào yī bēi bīng de ná tiě, shǎo bīng.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 bing1 de0 na2 tie3, shao3 bing1.",
      "translation_en": "I would like an iced latte with less ice.",
      "translation_ko": "얼음 적게 넣은 아이스 라떼 한 잔을 원합니다."
    },
    {
      "text": "我想要一杯紅茶，外帶。",
      "pinyin": "Wǒ xiǎng yào yī bēi hóng chá, wài dài.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 hong2 cha2, wai4 dai4.",
      "translation_en": "I would like a black tea to go.",
      "translation_ko": "홍차 한 잔을 테이크아웃으로 원합니다."
    },
    {
      "text": "我想要一杯綠茶，內用。",
      "pinyin": "Wǒ xiǎng yào yī bēi lǜ chá, nèi yòng.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 lü4 cha2, nei4 yong4.",
      "translation_en": "I would like a green tea for here.",
      "translation_ko": "녹차 한 잔을 매장에서 마시고 싶습니다."
    },
    {
      "text": "我想要一杯拿鐵，正常甜。",
      "pinyin": "Wǒ xiǎng yào yī bēi ná tiě, zhèng cháng tián.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 na2 tie3, zheng4 chang2 tian2.",
      "translation_en": "I would like a latte with regular sweetness.",
      "translation_ko": "일반 당도의 라떼 한 잔을 원합니다."
    },
    {
      "text": "我想要一杯豆漿，微糖。",
      "pinyin": "Wǒ xiǎng yào yī bēi dòu jiāng, wēi táng.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4 jiang1, wei1 tang2.",
      "translation_en": "I would like a cup of soy milk with less sugar.",
      "translation_ko": "당을 적게 넣은 두유 한 잔을 원합니다."
    },
    {
      "text": "我想要一杯冰的紅茶，加珍珠。",
      "pinyin": "Wǒ xiǎng yào yī bēi bīng de hóng chá, jiā zhēn zhū.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 bing1 de0 hong2 cha2, jia1 zhen1 zhu1.",
      "translation_en": "I would like an iced black tea with tapioca pearls.",
      "translation_ko": "타피오카 펄을 추가한 아이스 홍차 한 잔을 원합니다."
    }
  ]
